import * as os from 'os';
import * as path from 'path';

import { Injectable, Logger, OnModuleDestroy, OnModuleInit } from '@nestjs/common';
import { Piscina } from 'piscina';

import { IStyleColorBase } from '@modules/db/style-colors/types/style-color.base.interface';
import { EnvConfigService } from '@modules/env-config/env-config.service';

import { convertStringToRGB, getColorRGBToIdHash } from '@utils/color-match.util';

import { NODE_ENV } from '@constants/env-variables.constant';

import { IProductColor } from '@interfaces/algolia-hits.interface';

@Injectable()
export class ColorMatchWorkerService implements OnModuleInit, OnModuleDestroy {
	private readonly logger = new Logger(ColorMatchWorkerService.name);
	private pool!: Piscina;

	constructor(private readonly envConfigService: EnvConfigService) {}

	onModuleInit(): void {
		const isDevelopment =
			this.envConfigService.get<string>({ key: NODE_ENV }) === 'development';
		let workerPath: string;

		if (isDevelopment) {
			workerPath = path.join(
				process.cwd(),
				'src',
				'modules',
				'color-match-worker',
				'color-match.worker.ts',
			);
		} else {
			workerPath = path.resolve(__dirname, 'color-match.worker.js');
		}

		const cpuCount = os.availableParallelism?.() ?? os.cpus().length;

		this.pool = new Piscina({
			filename: workerPath,
			minThreads: 1,
			maxThreads: Math.max(1, cpuCount - 1),
			idleTimeout: 30000,
			...(isDevelopment && {
				execArgv: [
					'--require',
					'ts-node/register',
					'--require',
					'tsconfig-paths/register',
				],
			}),
		});

		this.logger.log(
			`Color match worker pool initialized: workerPath=${workerPath}, minThreads=1, maxThreads=${Math.max(1, cpuCount - 1)}`,
		);
	}

	async onModuleDestroy(): Promise<void> {
		if (this.pool) {
			await this.pool.destroy();
			this.logger.log('Color match worker pool destroyed');
		}
	}

	async findClosestColorId({
		color,
		palette,
	}: {
		color: IStyleColorBase | null;
		palette: IProductColor[];
	}): Promise<number> {
		if (!color || !palette.some((item) => item.rbgs?.length)) {
			this.logger.warn(
				'[findClosestColorId]: No color or palette provided, defaulting to color ID 0',
			);
			return 0;
		}

		const referenceColor = palette.find((item) => item.name === color.color_name);

		if (referenceColor) {
			this.logger.debug(
				`[findClosestColorId]: Exact color match found for "${color.color_name}", using color ID ${referenceColor.id}`,
			);
			return referenceColor.id;
		}

		const selectedColorRGB = color.color_rgb;

		if (!selectedColorRGB || !palette.length) {
			this.logger.warn(
				'[findClosestColorId]: No selected color RGB or empty palette, defaulting to color ID 0',
			);
			return 0;
		}

		const colorsHash = getColorRGBToIdHash({ colors: palette });

		const paletteColors = palette.reduce<{ R: number; G: number; B: number }[]>(
			(acc, color) => {
				if (color.rbgs?.[0]) {
					acc.push(color.rbgs[0]);
				}
				return acc;
			},
			[],
		);

		const closestColorId = (await this.pool.run({
			selectedColorRGB: convertStringToRGB({ str: selectedColorRGB }),
			paletteColors,
			colorsHash,
		})) as number;

		this.logger.debug(
			`[findClosestColorId]: Closest color to "${color.color_name}" (RGB: ${selectedColorRGB}) is color ID ${closestColorId}. colorsHash: ${JSON.stringify(colorsHash)}, paletteColors: ${JSON.stringify(paletteColors)}`,
		);

		return closestColorId;
	}
}

