import { Test, TestingModule } from '@nestjs/testing';

import { BigQueryService } from '@modules/bigquery/bigquery.service';
import { PopulateStyleCopurchasesCommand } from '@modules/cli/commands/populate-style-copurchases.command';
import { StyleCopurchasesService } from '@modules/db/style-copurchases/style-copurchases.service';

jest.mock('@config/rollbar.config', () => ({
	rollbar: {
		debug: jest.fn(),
		error: jest.fn(),
		warning: jest.fn(),
		info: jest.fn(),
		wait: jest.fn((cb: () => void) => {
			cb();
		}),
	},
}));

describe('PopulateStyleCopurchasesCommand', () => {
	let command: PopulateStyleCopurchasesCommand;
	let mockBigQueryService: jest.Mocked<BigQueryService>;
	let mockStyleCopurchasesService: jest.Mocked<StyleCopurchasesService>;
	let processExitSpy: jest.SpyInstance;

	beforeEach(async () => {
		jest.clearAllMocks();
		jest.useFakeTimers();

		processExitSpy = jest.spyOn(process, 'exit').mockImplementation(() => {
			return undefined as never;
		});

		mockBigQueryService = {
			fetchStyleCopurchases: jest.fn(),
		} as unknown as jest.Mocked<BigQueryService>;

		mockStyleCopurchasesService = {
			bulkInsert: jest.fn(),
			clearExistingData: jest.fn(),
		} as unknown as jest.Mocked<StyleCopurchasesService>;

		const module: TestingModule = await Test.createTestingModule({
			providers: [
				PopulateStyleCopurchasesCommand,
				{ provide: BigQueryService, useValue: mockBigQueryService },
				{ provide: StyleCopurchasesService, useValue: mockStyleCopurchasesService },
			],
		}).compile();

		command = module.get<PopulateStyleCopurchasesCommand>(
			PopulateStyleCopurchasesCommand,
		);
	});

	afterEach(() => {
		processExitSpy.mockRestore();
		jest.useRealTimers();
	});

	describe('run', () => {
		it('should fetch data, truncate, and insert', async () => {
			const mockRows = [
				{ style_a_id: 100, style_b_id: 200, co_purchase_count: 5 },
				{ style_a_id: 300, style_b_id: 400, co_purchase_count: 3 },
			];
			mockBigQueryService.fetchStyleCopurchases.mockResolvedValueOnce(mockRows);
			mockStyleCopurchasesService.clearExistingData.mockResolvedValueOnce(undefined);
			mockStyleCopurchasesService.bulkInsert.mockResolvedValueOnce(undefined);

			await command.run();

			expect(mockBigQueryService.fetchStyleCopurchases).toHaveBeenCalledTimes(1);
			expect(mockStyleCopurchasesService.clearExistingData).toHaveBeenCalledTimes(1);
			expect(mockStyleCopurchasesService.bulkInsert).toHaveBeenCalledWith([
				{ styleIdA: 100, styleIdB: 200, copurchaseCount: 5 },
				{ styleIdA: 300, styleIdB: 400, copurchaseCount: 3 },
			]);
		});

		it('should skip truncate and insert when BigQuery returns empty result', async () => {
			mockBigQueryService.fetchStyleCopurchases.mockResolvedValueOnce([]);

			await command.run();

			expect(mockStyleCopurchasesService.clearExistingData).not.toHaveBeenCalled();
			expect(mockStyleCopurchasesService.bulkInsert).not.toHaveBeenCalled();
		});

		it('should exit with code 1 when BigQuery fails', async () => {
			mockBigQueryService.fetchStyleCopurchases.mockRejectedValueOnce(
				new Error('BQ error'),
			);

			await command.run();

			expect(mockStyleCopurchasesService.bulkInsert).not.toHaveBeenCalled();
			expect(processExitSpy).toHaveBeenCalledWith(1);
		});

		it('should return early when isShuttingDown is true', async () => {
			(command as unknown as { isShuttingDown: boolean }).isShuttingDown = true;

			await command.run();

			expect(mockBigQueryService.fetchStyleCopurchases).not.toHaveBeenCalled();
		});

		it('should not log success when shutdown occurs after upsert', async () => {
			const mockRows = [{ style_a_id: 100, style_b_id: 200, co_purchase_count: 5 }];
			mockBigQueryService.fetchStyleCopurchases.mockResolvedValueOnce(mockRows);
			mockStyleCopurchasesService.clearExistingData.mockResolvedValueOnce(undefined);
			// eslint-disable-next-line @typescript-eslint/require-await
			mockStyleCopurchasesService.bulkInsert.mockImplementation(async () => {
				(command as unknown as { isShuttingDown: boolean }).isShuttingDown = true;
			});

			await command.run();

			expect(mockStyleCopurchasesService.bulkInsert).toHaveBeenCalledTimes(1);
		});

		it('should return early in catch block when shutting down during error', async () => {
			// eslint-disable-next-line @typescript-eslint/require-await
			mockBigQueryService.fetchStyleCopurchases.mockImplementation(async () => {
				(command as unknown as { isShuttingDown: boolean }).isShuttingDown = true;
				throw new Error('interrupted');
			});

			await command.run();

			expect(processExitSpy).not.toHaveBeenCalledWith(1);
		});
	});

	describe('handleShutdown', () => {
		it('should set isShuttingDown and exit with 0 when no current operation', async () => {
			await (
				command as unknown as { handleShutdown: (signal: string) => Promise<void> }
			).handleShutdown('SIGTERM');

			expect((command as unknown as { isShuttingDown: boolean }).isShuttingDown).toBe(
				true,
			);
			expect(processExitSpy).toHaveBeenCalledWith(0);
		});

		it('should force exit when already shutting down', async () => {
			(command as unknown as { isShuttingDown: boolean }).isShuttingDown = true;

			await (
				command as unknown as { handleShutdown: (signal: string) => Promise<void> }
			).handleShutdown('SIGTERM');

			expect(processExitSpy).toHaveBeenCalledWith(1);
		});

		it('should wait for current operation and then exit', async () => {
			(
				command as unknown as { currentOperation: Promise<void> | null }
			).currentOperation = Promise.resolve();

			await (
				command as unknown as { handleShutdown: (signal: string) => Promise<void> }
			).handleShutdown('SIGTERM');

			expect(processExitSpy).toHaveBeenCalledWith(0);
		});

		it('should exit with 1 when current operation rejects', async () => {
			(
				command as unknown as { currentOperation: Promise<void> | null }
			).currentOperation = Promise.reject(new Error('operation failed'));

			await (
				command as unknown as { handleShutdown: (signal: string) => Promise<void> }
			).handleShutdown('SIGINT');

			expect(processExitSpy).toHaveBeenCalledWith(1);
		});

		it('should force exit on shutdown timeout', async () => {
			let resolveOp: () => void;
			(
				command as unknown as { currentOperation: Promise<void> | null }
			).currentOperation = new Promise<void>((resolve) => {
				resolveOp = resolve;
			});

			const shutdownPromise = (
				command as unknown as { handleShutdown: (signal: string) => Promise<void> }
			).handleShutdown('SIGTERM');

			jest.advanceTimersByTime(30000);

			expect(processExitSpy).toHaveBeenCalledWith(1);

			resolveOp!();
			await shutdownPromise;
		});
	});

	describe('setupGracefulShutdown', () => {
		it('should handle signal by calling handleShutdown', () => {
			const handleShutdownSpy = jest.spyOn(
				command as unknown as { handleShutdown: (signal: string) => Promise<void> },
				'handleShutdown',
			);
			handleShutdownSpy.mockResolvedValue(undefined);

			process.emit('SIGHUP', 'SIGHUP');

			expect(handleShutdownSpy).toHaveBeenCalledWith('SIGHUP');
			handleShutdownSpy.mockRestore();
		});

		it('should handle uncaughtException by calling handleShutdown', () => {
			const handleShutdownSpy = jest.spyOn(
				command as unknown as { handleShutdown: (signal: string) => Promise<void> },
				'handleShutdown',
			);
			handleShutdownSpy.mockResolvedValue(undefined);

			process.emit('uncaughtException', new Error('test uncaught'));

			expect(handleShutdownSpy).toHaveBeenCalledWith('SIGTERM');
			handleShutdownSpy.mockRestore();
		});

		it('should handle unhandledRejection by calling handleShutdown', () => {
			const handleShutdownSpy = jest.spyOn(
				command as unknown as { handleShutdown: (signal: string) => Promise<void> },
				'handleShutdown',
			);
			handleShutdownSpy.mockResolvedValue(undefined);

			process.emit('unhandledRejection', 'test rejection', Promise.resolve());

			expect(handleShutdownSpy).toHaveBeenCalledWith('SIGTERM');
			handleShutdownSpy.mockRestore();
		});
	});
});

